#!/usr/bin/env node
/**
 * Post-build patch for a Turbopack bug in Next.js 16 where external packages
 * listed in `serverExternalPackages` get a content-hash suffix appended to
 * their name in the generated `require()` calls, e.g.:
 *
 *   require("firebase-admin-e80223cff3f2baca")  // generated by Turbopack
 *
 * At Cloud Run runtime there is no package named "firebase-admin-<hash>" in
 * node_modules, so every dynamic route returns 500 before any user code runs.
 *
 * This script walks .next/server/chunks after `next build` and strips the
 * hash suffix so the require resolves to the real package name.
 *
 * It is invoked automatically via the "postbuild" npm script.
 */

const fs = require('fs');
const path = require('path');

const CHUNKS_DIR = path.join(__dirname, '..', '.next', 'server', 'chunks');

// Matches any package name followed by a 16-hex-char Turbopack hash, e.g.
//   "firebase-admin-e80223cff3f2baca" or "firebase-admin-e80223cff3f2baca/app"
// Only fixes packages that are in serverExternalPackages (firebase-admin, grpc…)
// by matching the specific pattern used by Turbopack externals.
const HASH_PATTERN = /(["'])(firebase-admin|google-auth-library|google-gax|@grpc\/grpc-js|@grpc\/proto-loader)-([0-9a-f]{16})(\/?.*?)(["'])/g;

function walkDir(dir) {
  if (!fs.existsSync(dir)) return [];
  const result = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) result.push(...walkDir(full));
    else if (entry.name.endsWith('.js')) result.push(full);
  }
  return result;
}

let patchedFiles = 0;
let patchedOccurrences = 0;

for (const file of walkDir(CHUNKS_DIR)) {
  const original = fs.readFileSync(file, 'utf8');
  if (!HASH_PATTERN.test(original)) continue;

  HASH_PATTERN.lastIndex = 0; // reset after test()
  const patched = original.replace(HASH_PATTERN, '$1$2$4$5');
  if (patched === original) continue;

  const occurrences = (original.match(HASH_PATTERN) || []).length;
  fs.writeFileSync(file, patched);
  patchedFiles++;
  patchedOccurrences += occurrences;
  console.log(`  patched ${occurrences} occurrence(s) in ${path.relative(process.cwd(), file)}`);
}

if (patchedFiles === 0) {
  console.log('patch-turbopack-externals: nothing to patch');
} else {
  console.log(`patch-turbopack-externals: fixed ${patchedOccurrences} reference(s) across ${patchedFiles} file(s)`);
}
